player.updateHealthDisplay = function() { if (healthValue) healthValue.textContent = `${Math.floor(this.health)}/${this.maxHealth}`; if (healthFill) healthFill.style.width = `${(this.health / this.maxHealth) * 100}%`; };

function applyHealing(amount) {
    if (player.health >= player.maxHealth || amount <= 0) return;
    pendingHealing += Math.ceil(amount);
    const healAmount = Math.min(pendingHealing, player.maxHealth - player.health);
    if (healAmount > 0) {
        player.health += healAmount;
        pendingHealing -= healAmount;
        createHealthPopup(player.x, player.y, healAmount);
        addVisualEffect({ type: 'heal', x: player.x, y: player.y, radius: 20, color: '#00FF00', startTime: Date.now(), duration: 400 });
    }
    if (player.updateHealthDisplay) player.updateHealthDisplay();
}

function getTargetPriority(monster, player, weapon, currentTime) {
    const dx = monster.x - player.x, dy = monster.y - player.y, dist = Math.hypot(dx, dy);
    if (dist > weapon.range) return -Infinity;
    let score = 10000 - dist;
    const angleDiff = (() => { let a = Math.atan2(dy, dx) - (player.facingAngle || 0); while (a > Math.PI) a -= Math.PI * 2; while (a < -Math.PI) a += Math.PI * 2; return a; })();
    score += Math.max(0, Math.cos(angleDiff)) * 300;
    if (attackedMonsters.has(monster)) score -= 200;
    let targetCount = 0; weaponTargets.forEach((t, id) => { if (t === monster && id !== weapon.id) targetCount++; });
    score -= targetCount * 150;
    if (weapon.sniper) { score += monster.health * 1.5; if (dist > 200 && dist < 500) score += 200; }
    else if (weapon.id === 'shotgun') { let nearby = 0; monsters.forEach(o => { if (o !== monster && Math.hypot(o.x - monster.x, o.y - monster.y) < 100) nearby++; }); score += nearby * 80; if (dist < 150) score += 300; }
    else if (weapon.id === 'crossbow') { score += Math.max(0, Math.cos(angleDiff)) * 250; let lined = 0; monsters.forEach(o => { if (o !== monster && Math.abs(Math.sin(angleDiff) * 100) < 50) lined++; }); score += lined * 100; }
    else if (weapon.id === 'throwing_knives') { score += (1 - monster.health / monster.maxHealth) * 400; if (dist < 150) score += 200; }
    else if (weapon.id === 'boomerang') { let nearby = 0; monsters.forEach(o => { if (o !== monster && Math.hypot(o.x - monster.x, o.y - monster.y) < 150) nearby++; }); score += nearby * 120; }
    else if (weapon.id === 'laser') { let lined = 0; monsters.forEach(o => { if (o !== monster && Math.abs(Math.sin(angleDiff) * 100) < 30) lined++; }); score += lined * 150; }
    else if (weapon.meleeType === 'aoe') { let nearby = 0; monsters.forEach(o => { if (o !== monster && Math.hypot(o.x - monster.x, o.y - monster.y) < weapon.range * 1.5) nearby++; }); score += nearby * 100; if (dist < weapon.range) score += 150; }
    else if (weapon.meleeType === 'pierce') { score += Math.max(0, Math.cos(angleDiff)) * 200; if (dist > weapon.range * 0.7) score += 100; }
    else if (weapon.meleeType === 'single' && dist < 80) score += 500;
    if (dist < 50) score += 2000;
    if (monster.isBoss) score += 3000;
    if (monster.isSplitter) score += 500;
    if (monster.explosive) score += 400;
    if (monster.isGunner) score += 300;
    if (monster.isDasher) score += 250;
    if (monster.isVampire) score += 350;
    return score;
}

function selectTargetForWeapon(weapon, currentTime) {
    if (monsters.length === 0) return null;
    let best = null, bestScore = -Infinity;
    monsters.forEach(m => { const s = getTargetPriority(m, player, weapon, currentTime); if (s > bestScore) { bestScore = s; best = m; } });
    return best;
}

function spawnRandomLandmine() {
    if (playerTowers.landmines.count <= 0 || playerTowers.landmines.active.length >= playerTowers.landmines.count) return;
    let x, y, valid = false;
    for (let a = 0; a < 100; a++) {
        x = 50 + Math.random() * (canvas.width - 100);
        y = 50 + Math.random() * (canvas.height - 100);
        if (Math.hypot(x - player.x, y - player.y) < 100) continue;
        let tooClose = false;
        for (let m of playerTowers.landmines.active) if (Math.hypot(x - m.x, y - m.y) < 50 + m.radius) { tooClose = true; break; }
        if (!tooClose) { valid = true; break; }
    }
    if (!valid) { x = 100 + Math.random() * (canvas.width - 200); y = 100 + Math.random() * (canvas.height - 200); }
    playerTowers.landmines.active.push({ x, y, radius: 15, damage: 80, explosionRadius: 60, active: true, startTime: Date.now(), color: '#8B4513' });
    addVisualEffect({ type: 'landmineSpawn', x, y, radius: 20, color: '#8B4513', startTime: Date.now(), duration: 500 });
    queueMessage(`Landmine deployed! (${playerTowers.landmines.active.length}/${playerTowers.landmines.count})`);
}

function checkLandmineTriggers() {
    for (let i = playerTowers.landmines.active.length - 1; i >= 0; i--) {
        const mine = playerTowers.landmines.active[i];
        for (let j = 0; j < monsters.length; j++) {
            if (Math.hypot(monsters[j].x - mine.x, monsters[j].y - mine.y) < mine.radius + monsters[j].radius) {
                for (let k = monsters.length - 1; k >= 0; k--) {
                    if (Math.hypot(monsters[k].x - mine.x, monsters[k].y - mine.y) < mine.explosionRadius + monsters[k].radius) {
                        monsters[k].health -= mine.damage;
                        createDamageIndicator(monsters[k].x, monsters[k].y, mine.damage, true);
                        if (monsters[k].health <= 0) handleMonsterDeath(monsters[k], k);
                    }
                }
                addVisualEffect({ type: 'explosion', x: mine.x, y: mine.y, radius: mine.explosionRadius, color: '#FF4500', startTime: Date.now(), duration: 400 });
                playerTowers.landmines.active.splice(i, 1);
                break;
            }
        }
    }
}

function placeHealingTower() {
    if (playerTowers.healingTowers.active.length >= 3) { queueMessage("Maximum towers reached (3)!"); return false; }
    playerTowers.healingTowers.active.push({ x: player.x, y: player.y, radius: 20, health: 30, healAmount: 1, lastHeal: Date.now(), id: Date.now() + Math.random() });
    addVisualEffect({ type: 'towerSpawn', x: player.x, y: player.y, radius: 30, color: '#4CAF50', startTime: Date.now(), duration: 500 });
    queueMessage(`Healing Tower placed! (${playerTowers.healingTowers.active.length}/3)`);
    return true;
}

function updateHealingTowers(ct) { playerTowers.healingTowers.active.forEach(t => { if (ct - t.lastHeal >= 2000 && player.health < player.maxHealth) { applyHealing(t.healAmount); t.lastHeal = ct; } }); }
function drawHealingTowers() { playerTowers.healingTowers.active.forEach(t => { ctx.save(); ctx.translate(t.x, t.y); ctx.fillStyle = '#8B4513'; ctx.fillRect(-10, -10, 20, 30); const p = Math.sin(Date.now() * 0.005) * 0.2 + 0.8; ctx.shadowColor = '#4CAF50'; ctx.shadowBlur = 15 * p; ctx.fillStyle = '#4CAF50'; ctx.beginPath(); ctx.moveTo(0, -25); ctx.lineTo(12, -10); ctx.lineTo(0, 5); ctx.lineTo(-12, -10); ctx.closePath(); ctx.fill(); ctx.shadowBlur = 0; ctx.fillStyle = '#000'; ctx.fillRect(-15, -35, 30, 4); ctx.fillStyle = t.health / 30 > 0.5 ? '#0F0' : '#F00'; ctx.fillRect(-15, -35, 30 * (t.health / 30), 4); if (Date.now() - t.lastHeal < 500) { ctx.strokeStyle = '#FFF'; ctx.lineWidth = 2; ctx.shadowBlur = 10; ctx.shadowColor = '#0F0'; ctx.beginPath(); ctx.arc(0, -10, 15 + p * 3, 0, Math.PI * 2); ctx.stroke(); } ctx.restore(); }); }
function findPathToTarget(enemy, target) { const dx = target.x - enemy.x, dy = target.y - enemy.y, d = Math.hypot(dx, dy); if (d < 5) return { x: 0, y: 0 }; let mx = dx / d, my = dy / d; for (let t of playerTowers.healingTowers.active) { if (t === target) continue; const td = Math.hypot(t.x - enemy.x, t.y - enemy.y); if (td < 50) { const ax = (enemy.x - t.x) / td, ay = (enemy.y - t.y) / td; mx = (mx + ax * 0.5) / 1.5; my = (my + ay * 0.5) / 1.5; const nd = Math.hypot(mx, my); mx /= nd; my /= nd; } } return { x: mx, y: my }; }
function placeBomb() { const b = { x: player.x, y: player.y, radius: 20, damage: 100, explosionRadius: 150, active: true, startTime: Date.now(), detonateTime: Date.now() + 2000, color: '#F00' }; placedBombs.push(b); addVisualEffect({ type: 'bombPlaced', x: b.x, y: b.y, radius: 20, color: '#F00', startTime: Date.now(), duration: 2000 }); queueMessage("Bomb placed! 2 second fuse..."); setTimeout(() => detonateBomb(b), 2000); }
function detonateBomb(b) { if (!b.active) return; let hit = 0; for (let i = monsters.length - 1; i >= 0; i--) { if (Math.hypot(monsters[i].x - b.x, monsters[i].y - b.y) < b.explosionRadius + monsters[i].radius) { monsters[i].health -= b.damage; createDamageIndicator(monsters[i].x, monsters[i].y, b.damage, true); hit++; if (monsters[i].health <= 0) handleMonsterDeath(monsters[i], i); } } addVisualEffect({ type: 'explosion', x: b.x, y: b.y, radius: b.explosionRadius, color: '#FF4500', startTime: Date.now(), duration: 400 }); const idx = placedBombs.indexOf(b); if (idx > -1) placedBombs.splice(idx, 1); b.active = false; queueMessage(hit > 0 ? `Boom! Hit ${hit} monsters!` : "Bomb exploded but missed everything!"); }
function useBomb() { placeBomb(); }
function activateRagePotion() { activeBuffs.rage.active = true; activeBuffs.rage.originalMultiplier = player.damageMultiplier; activeBuffs.rage.endTime = Date.now() + 10000; player.damageMultiplier *= 1.5; addVisualEffect({ type: 'rage', x: player.x, y: player.y, radius: 50, color: '#F00', startTime: Date.now(), duration: 10000 }); queueMessage("RAGE! +50% damage for 10 seconds!"); setTimeout(() => { if (activeBuffs.rage.active) { activeBuffs.rage.active = false; player.damageMultiplier = activeBuffs.rage.originalMultiplier; queueMessage("Rage effect ended"); } }, 10000); }
function useExpScroll() { if (player.weapons.length === 0) { queueMessage("No weapons to upgrade!"); return; } const up = player.weapons.filter(w => w.tier < 5); if (up.length === 0) { queueMessage("All weapons are already max tier (5)!"); return; } const w = up[Math.floor(Math.random() * up.length)]; const old = w.tier; w.tier++; w.applyTierBonuses(); if (w.resetEachRound) w.resetAmmo(); addVisualEffect({ type: 'upgrade', x: player.x, y: player.y, radius: 40, color: '#FFD700', startTime: Date.now(), duration: 1000 }); queueMessage(`${w.name} upgraded from Tier ${old} to Tier ${w.tier}!`); updateWeaponDisplay(); }
function createMessageContainer() { messageContainer = document.createElement('div'); messageContainer.id = 'messageContainer'; messageContainer.className = 'message-container'; document.body.appendChild(messageContainer); }
function queueMessage(text, dur = 2000) { messageQueue.push({ text, duration: dur }); if (messageQueue.length === 1) showNextMessage(); }
