function spawnAsteroid() { if (!waveActive) return; const boss = monsters.find(m => m.isBoss); if (!boss) return; const a = Math.random() * Math.PI * 2, d = 150 + Math.random() * 100, x = boss.x + Math.cos(a) * d, y = boss.y + Math.sin(a) * d, r = 40; addVisualEffect({ type: 'asteroidWarning', x, y, radius: r, startTime: Date.now(), duration: 800 }); setTimeout(() => { if (!waveActive) return; if (Math.hypot(player.x - x, player.y - y) < r + player.radius) { player.health -= 25; createDamageIndicator(player.x, player.y, 25, true); if (player.health <= 0) gameOver(); } for (let i = monsters.length - 1; i >= 0; i--) { const m = monsters[i]; if (Math.hypot(m.x - x, m.y - y) < r + m.radius && !m.isBoss) { m.health -= 75; createDamageIndicator(m.x, m.y, 75, true); if (m.health <= 0) handleMonsterDeath(m, i); } } addVisualEffect({ type: 'asteroid', x, y, radius: r, startTime: Date.now(), duration: 500 }); }, 800); }
function handleSplitterDeath(m) { if (!m.isSplitter) return; const cnt = m.splitCount || 2, hp = Math.floor(m.maxHealth * (m.splitHealthPercent || 0.5)); for (let i = 0; i < cnt; i++) { const a = (i / cnt) * Math.PI * 2, d = 30; monsters.push({ ...m, x: m.x + Math.cos(a) * d, y: m.y + Math.sin(a) * d, health: hp, maxHealth: hp, radius: m.radius * 0.7, isSplitter: false, color: '#aaffaa', originalSpeed: m.originalSpeed * 1.2 }); } addVisualEffect({ type: 'explosion', x: m.x, y: m.y, radius: 50, color: '#0F0', startTime: Date.now(), duration: 300 }); }
function updateDasher(d, ct) { if (!d.isDasher) return; if (d.isDashing) { const dx = d.dashTarget.x - d.x, dy = d.dashTarget.y - d.y, dist = Math.hypot(dx, dy); if (dist < 5) { d.isDashing = false; d.speed = d.originalSpeed; } else { d.x += (dx / dist) * d.dashSpeed; d.y += (dy / dist) * d.dashSpeed; } } else if (ct - d.lastDash >= d.dashCooldown && Math.hypot(player.x - d.x, player.y - d.y) < 300) { d.isDashing = true; d.dashTarget = { x: player.x, y: player.y }; d.lastDash = ct; addVisualEffect({ type: 'shockwave', x: d.x, y: d.y, radius: 30, color: '#0FF', startTime: ct, duration: 200 }); } }
function handleMonsterDeath(m, idx) { attackedMonsters.delete(m); weaponTargets.forEach((t, wid) => { if (t === m) weaponTargets.delete(wid); }); monsters.splice(idx, 1); player.weapons.forEach(w => { if (w.isThrowable) { const ret = w.returnKnives(m); if (ret > 0) createHealthPopup(m.x, m.y, ret); } }); let g = 0; if (m.monsterType && m.monsterType.goldDrop) g = Math.floor((Math.random() * (m.monsterType.goldDrop.max - m.monsterType.goldDrop.min + 1) + m.monsterType.goldDrop.min) * (1 + player.goldMultiplier)); else g = Math.floor((5 + Math.random() * 10) * (1 + player.goldMultiplier)); gold += g; kills++; createGoldPopup(m.x, m.y, g); addVisualEffect({ type: 'death', x: m.x, y: m.y, startTime: Date.now(), duration: 300 }); if (m.explosive) { const r = 100, dmg = m.damage * 2; addVisualEffect({ type: 'explosion', x: m.x, y: m.y, radius: r, color: '#FF4500', startTime: Date.now(), duration: 400 }); monsters.forEach((om, oi) => { if (om !== m && Math.hypot(om.x - m.x, om.y - m.y) < r + om.radius) { om.health -= dmg; createDamageIndicator(om.x, om.y, dmg, false); if (om.health <= 0) handleMonsterDeath(om, oi); } }); if (Math.hypot(player.x - m.x, player.y - m.y) < r + player.radius) { player.health -= dmg; createDamageIndicator(player.x, player.y, dmg, false); if (player.health <= 0) gameOver(); } } if (m.isSplitter) handleSplitterDeath(m); if (m.isDasher) { const di = dashers.indexOf(m); if (di > -1) dashers.splice(di, 1); } if (player.berserkerRing) player.damageMultiplier = (player.baseDamageMultiplier || 1.0) + (1 - player.health / player.maxHealth) * 0.5; updateUI(); }
function updateUI() { healthValue.textContent = `${Math.floor(player.health)}/${player.maxHealth}`; damageValue.textContent = (player.damageMultiplier * 100).toFixed(0) + '%'; speedValue.textContent = (player.speedMultiplier * 100).toFixed(0) + '%'; goldValue.textContent = gold; waveValue.textContent = wave; killsValue.textContent = kills; const hpPct = (player.health / player.maxHealth) * 100; healthFill.style.width = `${hpPct}%`; healthFill.style.background = hpPct > 60 ? 'linear-gradient(90deg, #11998e, #38ef7d)' : (hpPct > 30 ? 'linear-gradient(90deg, #f7971e, #ffd200)' : 'linear-gradient(90deg, #ff416c, #ff4b2b)'); monsterCount.textContent = `Monsters: ${monsters.length}`; if (statsPanelVisible) updateStatsPanel(); }
function updateWeaponDisplay() { weaponsGrid.innerHTML = ''; const ct = Date.now(); for (let i = 0; i < 6; i++) { const slot = document.createElement('div'); slot.className = 'weapon-slot'; if (i < player.weapons.length) { const w = player.weapons[i]; slot.classList.add('occupied'); if (selectedWeaponIndex === i) slot.classList.add('selected'); if (mergeTargetIndex === i) { slot.style.borderColor = '#0F0'; slot.style.boxShadow = '0 0 15px rgba(0,255,0,0.5)'; } let cd = 100; if (w.lastAttack > 0) { const cdTime = 1000 / (w.attackSpeed * player.attackSpeedMultiplier); cd = Math.min(100, ((ct - w.lastAttack) / cdTime) * 100); } const effDmg = Math.floor(w.baseDamage * player.damageMultiplier); let ammoHtml = ''; if (w.usesAmmo) ammoHtml = w.isThrowable ? `<div class="throwable-ammo-small"><span class="ammo-count">${w.currentAmmo}</span><span class="ammo-max">/${w.magazineSize}</span></div>` : `<div class="ammo-display">${w.currentAmmo}/${w.magazineSize}</div>`; slot.innerHTML = `<div>${w.icon}</div>${w.tier > 1 ? `<div class="tier-badge">${w.tier}</div>` : ''}<div class="weapon-level">${w.type === 'melee' ? '⚔️' : '🔫'}</div><div class="melee-type">${w.getTypeDescription()}</div>${ammoHtml}<div class="weapon-info">${w.getDisplayName()}<br>Base: ${w.baseDamage}<br>Total: ${effDmg}<br>Spd: ${(w.attackSpeed * player.attackSpeedMultiplier).toFixed(1)}/s</div><div class="cooldown-bar"><div class="cooldown-fill" style="width: ${cd}%; ${w.isReloading ? 'background: linear-gradient(90deg, #ff0000, #ff8800);' : ''}"></div></div>`; slot.addEventListener('click', (e) => { e.preventDefault(); selectWeapon(i); }); slot.addEventListener('touchstart', (e) => { e.preventDefault(); selectWeapon(i); }); } else { slot.innerHTML = '<div class="empty-slot">+</div>'; } weaponsGrid.appendChild(slot); } }
function updateConsumablesDisplay() { if (!consumablesGrid) return; consumablesGrid.innerHTML = ''; if (player.consumables.length === 0) { consumablesGrid.innerHTML = '<div class="empty-consumable">No consumables</div>'; return; } player.consumables.forEach((c, idx) => { const slot = document.createElement('div'); slot.className = 'consumable-slot'; slot.innerHTML = `<div class="consumable-icon">${c.icon}</div><div class="consumable-name">${c.name}</div><div class="consumable-count">${c.count || 1}</div>`; slot.addEventListener('click', (e) => { e.preventDefault(); useConsumable(idx); }); slot.addEventListener('touchstart', (e) => { e.preventDefault(); useConsumable(idx); }); consumablesGrid.appendChild(slot); }); }
function useConsumable(idx) { if (gameState !== 'wave') { queueMessage("Can only use consumables during waves!"); return; } const c = player.consumables[idx]; switch(c.id) { case 'health_potion': const heal = Math.floor(player.maxHealth * 0.25); applyHealing(heal); queueMessage(`Used Health Potion! +${heal} HP (25%)`); break; case 'ammo_pack': player.weapons.forEach(w => { if (w.usesAmmo && !w.isThrowable) { w.currentAmmo = w.magazineSize; w.isReloading = false; } }); queueMessage("Used Ammo Pack! All weapons reloaded"); break; case 'rage_potion': activateRagePotion(); break; case 'bomb': useBomb(); break; case 'exp_scroll': useExpScroll(); break; case 'healing_tower': placeHealingTower(); break; } if (c.count && c.count > 1) c.count--; else player.consumables.splice(idx, 1); updateConsumablesDisplay(); updateUI(); }
function selectWeapon(idx) { if (gameState !== 'shop' && gameState !== 'statSelect') return; if (idx >= player.weapons.length) return; const w = player.weapons[idx]; if (selectedWeaponIndex === -1) { selectedWeaponIndex = idx; scrapWeaponBtn.innerHTML = `<span class="icon">🗑️</span> Scrap ${w.getDisplayName()} (Get ${w.getScrapValue()} gold)`; scrapWeaponBtn.style.display = 'block'; mergeWeaponBtn.style.display = 'none'; mergeInfo.style.display = 'none'; mergeTargetIndex = -1; } else if (selectedWeaponIndex === idx) { selectedWeaponIndex = -1; scrapWeaponBtn.style.display = 'none'; mergeWeaponBtn.style.display = 'none'; mergeInfo.style.display = 'none'; mergeTargetIndex = -1; } else { const f = player.weapons[selectedWeaponIndex]; if (f.id === w.id && f.tier === w.tier) { mergeTargetIndex = idx; const cost = f.getMergeCost(w); if (cost > 0 && f.tier < 5) { mergeWeaponBtn.innerHTML = `<span class="icon">🔄</span> Merge ${f.getDisplayName()} + ${w.getDisplayName()} (Cost: ${cost} gold)`; mergeWeaponBtn.style.display = 'block'; mergeInfo.textContent = `Merge to create ${f.name} Tier ${f.tier + 1}!`; mergeInfo.style.display = 'block'; setTimeout(() => { mergeInfo.style.display = 'none'; }, 3000); } else { mergeInfo.textContent = f.tier >= 5 ? 'Max tier reached!' : 'Cannot merge these weapons'; mergeInfo.style.display = 'block'; setTimeout(() => { mergeInfo.style.display = 'none'; }, 2000); } } else { selectedWeaponIndex = idx; scrapWeaponBtn.innerHTML = `<span class="icon">🗑️</span> Scrap ${w.getDisplayName()} (Get ${w.getScrapValue()} gold)`; scrapWeaponBtn.style.display = 'block'; mergeWeaponBtn.style.display = 'none'; mergeInfo.style.display = 'none'; mergeTargetIndex = -1; } } updateWeaponDisplay(); }
function mergeWeapons() { if (selectedWeaponIndex === -1 || mergeTargetIndex === -1) return; const w1 = player.weapons[selectedWeaponIndex], w2 = player.weapons[mergeTargetIndex]; if (w1.id !== w2.id || w1.tier !== w2.tier) { queueMessage("Can only merge identical weapons of same tier!"); return; } if (w1.tier >= 5) { queueMessage("Maximum tier (5) reached!"); return; } const cost = w1.getMergeCost(w2); if (gold < cost) { queueMessage(`Need ${cost} gold to merge!`); return; } gold -= cost; const merged = w1.merge(w2); if (!merged) { queueMessage("Merge failed!"); return; } player.weapons[selectedWeaponIndex] = merged; player.weapons.splice(mergeTargetIndex, 1); selectedWeaponIndex = -1; mergeTargetIndex = -1; scrapWeaponBtn.style.display = 'none'; mergeWeaponBtn.style.display = 'none'; queueMessage(`Merged to create ${merged.getDisplayName()}!`); updateUI(); updateWeaponDisplay(); }
