function updateShopDisplay() { shopItemsContainer.innerHTML = ''; for (let i = 0; i < 4; i++) { const it = shopItems[i]; const el = document.createElement('div'); if (it) { el.className = 'shop-item'; const data = it.data; let cost = data.cost, tierText = '', tierClass = ''; if (it.type === 'weapon') { const tier = it.tier || 1; cost = new WeaponInstance(data, tier).getShopCost(); if (tier > 1) { tierText = ` Tier ${tier}`; tierClass = ` tier-${tier}`; } } let tagClass = ''; if (it.type === 'weapon') { if (data.type === 'melee') { if (data.meleeType === 'aoe') tagClass = 'aoe-tag'; else if (data.meleeType === 'pierce') tagClass = 'pierce-tag'; else if (data.meleeType === 'dual') tagClass = 'dual-tag'; else tagClass = 'single-tag'; } else { if (data.id === 'shotgun') tagClass = 'shotgun-tag'; else if (data.id === 'laser') tagClass = 'energy-tag'; else if (data.id === 'boomerang') tagClass = 'boomerang-tag'; else if (data.id === 'throwing_knives') tagClass = 'throwing-tag'; else if (data.id === 'sniper') tagClass = 'sniper-tag'; else if (data.id === 'crossbow') tagClass = 'crossbow-tag'; else tagClass = 'ranged-tag'; } } else if (it.type === 'tower') tagClass = 'tower-tag'; let typeText = ''; if (it.type === 'weapon') { if (data.id === 'shotgun') typeText = 'SHOTGUN'; else if (data.id === 'laser') typeText = 'ENERGY'; else if (data.id === 'boomerang') typeText = 'BOOMERANG'; else if (data.id === 'throwing_knives') typeText = 'THROWING'; else if (data.id === 'sniper') typeText = 'SNIPER'; else if (data.id === 'crossbow') typeText = 'CROSSBOW'; else if (data.type === 'melee') typeText = data.meleeType.toUpperCase(); else typeText = 'RANGED'; } else if (it.type === 'tower') typeText = 'TOWER'; else typeText = data.type === 'consumable' ? 'CONSUMABLE' : 'PERMANENT'; el.innerHTML = `<div class="item-info"><div class="item-name">${data.icon} ${data.name}${tierText}${tagClass ? `<span class="item-tag ${tagClass}${tierClass}">${typeText}</span>` : ''}</div><div class="item-effect">${data.description}</div></div><div class="item-cost">${cost}g</div>`; el.addEventListener('click', (e) => { e.preventDefault(); purchaseItem(i); }); el.addEventListener('touchstart', (e) => { e.preventDefault(); purchaseItem(i); }); } else { el.className = 'shop-item empty'; el.innerHTML = `<div class="item-info"><div class="item-name">Empty Slot</div><div class="item-effect">Already purchased</div></div><div class="item-cost">-</div>`; } shopItemsContainer.appendChild(el); } }
function purchaseItem(idx) { if (idx >= shopItems.length || !shopItems[idx]) return; const it = shopItems[idx], data = it.data; let cost = data.cost; if (it.type === 'weapon') cost = new WeaponInstance(data, it.tier || 1).getShopCost(); if (gold < cost) { queueMessage(`Not enough gold! Need ${cost}, have ${gold}`); return; } gold -= cost; if (it.type === 'weapon') { if (player.weapons.length >= 6) { queueMessage('No empty weapon slots!'); gold += cost; return; } player.weapons.push(new WeaponInstance(data, it.tier || 1)); queueMessage(`Purchased ${data.name} Tier ${it.tier || 1}!`); } else if (it.type === 'tower') { if (data.id === 'landmine') { if (playerTowers.landmines.count >= playerTowers.landmines.max) { queueMessage(`Maximum landmines (${playerTowers.landmines.max}) reached!`); gold += cost; return; } playerTowers.landmines.count++; queueMessage(`Purchased Landmine! (${playerTowers.landmines.count}/${playerTowers.landmines.max})`); if (gameState === 'wave') setTimeout(() => spawnRandomLandmine(), 100); } else if (data.id === 'healing_tower') { const ex = player.consumables.find(c => c.id === 'healing_tower'); if (ex) ex.count = (ex.count || 1) + 1; else player.consumables.push({ id: 'healing_tower', name: 'Healing Tower', icon: '🏥', count: 1 }); queueMessage(`Added Healing Tower to consumables!`); updateConsumablesDisplay(); } } else { if (data.type === 'consumable') { const ex = player.consumables.find(c => c.id === data.id); if (ex) ex.count = (ex.count || 1) + 1; else player.consumables.push({ id: data.id, name: data.name, icon: data.icon, count: 1 }); queueMessage(`Added ${data.name} to consumables!`); updateConsumablesDisplay(); } else { applyPermanentItemEffect(data); queueMessage(`Purchased ${data.name}!`); } } shopItems[idx] = null; updateUI(); updateWeaponDisplay(); updateShopDisplay(); }
function applyPermanentItemEffect(it) { switch(it.id) { case 'damage_orb': player.damageMultiplier += 0.15; queueMessage(`Damage increased by 15%! Now ${Math.floor(player.damageMultiplier * 100)}%`); break; case 'speed_boots': player.speedMultiplier += 0.15; player.speed = player.baseSpeed * player.speedMultiplier; queueMessage(`Speed increased by 15%! Now ${Math.floor(player.speedMultiplier * 100)}%`); break; case 'health_upgrade': const old = player.maxHealth; player.maxHealth = Math.floor(old * 1.25); player.health += player.maxHealth - old; queueMessage(`Max health increased by 25%! Now ${player.maxHealth}`); break; case 'vampire_teeth': player.lifeSteal += 0.05; queueMessage(`Life steal increased by 5%! Now ${Math.floor(player.lifeSteal * 100)}%`); break; case 'berserker_ring': player.berserkerRing = true; queueMessage("Berserker Ring equipped! Damage increases as health decreases"); break; case 'ninja_scroll': player.dodgeChance += 0.15; queueMessage(`Dodge chance increased by 15%! Now ${Math.floor(player.dodgeChance * 100)}%`); break; case 'alchemist_stone': player.goldMultiplier += 0.2; queueMessage(`Gold multiplier increased by 20%! Now +${Math.floor(player.goldMultiplier * 100)}% gold`); break; case 'thorns_armor': player.thornsDamage = 0.25; queueMessage("Thorns Armor equipped! Reflect 25% of damage back to attackers"); break; case 'wind_charm': player.attackSpeedMultiplier += 0.15; queueMessage(`Attack speed increased by 15%! Now ${player.attackSpeedMultiplier.toFixed(1)}x`); break; case 'runic_plate': player.firstHitReduction = true; player.firstHitActive = true; queueMessage("Runic Plate equipped! First hit each wave deals 50% less damage"); break; case 'guardian_angel': player.guardianAngel = true; queueMessage("Guardian Angel equipped! Once per game, survive fatal damage with 50% health"); break; case 'blood_contract': if (!player.bloodContract) { player.bloodContract = true; player.bloodContractStacks = 1; player.lifeSteal += 0.03; if (player.bloodContractInterval) clearInterval(player.bloodContractInterval); player.bloodContractInterval = setInterval(() => { if (gameState === 'wave') { const dmg = Math.max(1, Math.floor(player.maxHealth * 0.01 * player.bloodContractStacks)); if (player.health > dmg) player.health -= dmg; else player.health = 1; updateUI(); createDamageIndicator(player.x, player.y, dmg, false); } }, 1000); queueMessage(`Blood Contract activated! +3% lifesteal, lose ${player.bloodContractStacks}% HP per second`); } else { player.bloodContractStacks++; player.lifeSteal += 0.03; queueMessage(`Blood Contract stacked! Now ${player.bloodContractStacks} stacks (${Math.floor(player.lifeSteal * 100)}% lifesteal, lose ${player.bloodContractStacks}% HP per second)`); } break; } }
function showStatBuffs() { gameState = 'statSelect'; const buffs = generateStatBuffs(); statBuffs.innerHTML = ''; buffs.forEach(b => { const el = document.createElement('div'); el.className = 'stat-buff'; el.innerHTML = `<div class="buff-name">${b.icon} ${b.name}</div><div class="buff-description">${b.description}</div>`; el.addEventListener('click', (e) => { e.preventDefault(); selectStatBuff(b); }); el.addEventListener('touchstart', (e) => { e.preventDefault(); selectStatBuff(b); }); statBuffs.appendChild(el); }); waveCompleteOverlay.style.display = 'flex'; }
function selectStatBuff(buff) { if (buff.effect.maxHealthPercent) { const old = player.maxHealth; player.maxHealth = Math.floor(old * (1 + buff.effect.maxHealthPercent)); player.health += player.maxHealth - old; } if (buff.effect.damagePercent) player.damageMultiplier += buff.effect.damagePercent; if (buff.effect.speedPercent) { player.speedMultiplier += buff.effect.speedPercent; player.speed = player.baseSpeed * player.speedMultiplier; } if (buff.effect.lifeSteal) player.lifeSteal += buff.effect.lifeSteal; if (buff.effect.criticalChance) player.criticalChance += buff.effect.criticalChance; if (buff.effect.goldMultiplier) player.goldMultiplier += buff.effect.goldMultiplier; if (buff.effect.healthRegenPercent) player.healthRegenPercent += buff.effect.healthRegenPercent; if (buff.effect.damageReduction) player.damageReduction += buff.effect.damageReduction; if (buff.effect.reloadSpeedMultiplier) { player.reloadSpeedMultiplier += buff.effect.reloadSpeedMultiplier; queueMessage(`Reload speed increased by ${Math.floor(buff.effect.reloadSpeedMultiplier * 100)}%! Now ${(player.reloadSpeedMultiplier * 100).toFixed(0)}% faster`); } queueMessage(`Selected: ${buff.name}`); waveCompleteOverlay.style.display = 'none'; gameState = 'shop'; shopItems = generateShopItems(); updateShopDisplay(); updateUI(); nextWaveBtn.style.display = 'block'; scrapWeaponBtn.style.display = 'none'; mergeWeaponBtn.style.display = 'none'; selectedWeaponIndex = -1; mergeTargetIndex = -1; }
function endWave() { gameState = 'statSelect'; waveActive = false; playerTowers.landmines.active = []; placedBombs = []; player.inSlowField = false; player.slowFieldTicks = 0; player.speed = player.baseSpeed * player.speedMultiplier; if (asteroidTimer) clearInterval(asteroidTimer); if (minionSpawnInterval) clearInterval(minionSpawnInterval); bossAbilities = { shotgun: false, asteroids: [], slowField: null, enraged: false, bossWeapon: null, bossWeaponAttack: 0, bossDash: false, bossDashTarget: { x: 0, y: 0 }, bossDashStart: 0, bossDashCooldown: 0, bossDashDirection: { x: 0, y: 0 }, bossDashDistance: 0, minionSpawnTimer: 0 }; const wc = getWaveConfig(wave); gold += Math.floor(wc.goldReward * (1 + player.goldMultiplier)); player.weapons.forEach(w => { if (w.usesAmmo && !w.isThrowable) { w.currentAmmo = w.magazineSize; w.isReloading = false; } }); if (player.sharpeningStone && player.sharpeningStoneWave === wave) player.sharpeningStone = false; showStatBuffs(); }
function gameOver() { gameState = 'gameover'; waveActive = false; player.inSlowField = false; player.slowFieldTicks = 0; player.speed = player.baseSpeed * player.speedMultiplier; if (asteroidTimer) clearInterval(asteroidTimer); if (minionSpawnInterval) clearInterval(minionSpawnInterval); if (player.bloodContractInterval) clearInterval(player.bloodContractInterval); clearSave(); if (player.guardianAngel && !player.guardianAngelUsed && player.health <= 0) { player.guardianAngelUsed = true; player.health = Math.max(1, Math.floor(player.maxHealth * 0.5)); gameState = 'wave'; waveActive = true; queueMessage("GUARDIAN ANGEL SAVED YOU! 50% health restored."); addVisualEffect({ type: 'guardianAngel', x: player.x, y: player.y, radius: 50, color: '#FF0', startTime: Date.now(), duration: 1000 }); updateUI(); return; } gameOverText.textContent = `You survived ${wave} waves with ${kills} kills.`; gameOverOverlay.style.display = 'flex'; }
function showReloadIndicator(name) { if (gameState === 'wave') { reloadIndicator.textContent = `${name} - RELOADING...`; reloadIndicator.style.display = 'block'; setTimeout(() => { reloadIndicator.style.display = 'none'; }, 1000); } }

// ============================================
// GAME LOOP AND DRAWING
// ============================================

function gameLoop() {
    const ct = Date.now();
    const dt = ct - lastFrameTime;
    lastFrameTime = ct;
    if (gameState === 'wave') {
        let mx = 0, my = 0;
        if (keys.w || keys.up) my -= 1;
        if (keys.s || keys.down) my += 1;
        if (keys.a || keys.left) mx -= 1;
        if (keys.d || keys.right) mx += 1;
        if (joystickActive) {
            const str = Math.min(1, Math.hypot(joystickCurrentX, joystickCurrentY) / joystickMaxDistance);
            mx += (joystickCurrentX / joystickMaxDistance) * str;
            my += (joystickCurrentY / joystickMaxDistance) * str;
        }
        if (mx !== 0 || my !== 0) {
            const len = Math.hypot(mx, my);
            mx = mx / len * player.speed;
            my = my / len * player.speed;
            player.x += mx;
            player.y += my;
            player.x = Math.max(player.radius, Math.min(canvas.width - player.radius, player.x));
            player.y = Math.max(player.radius, Math.min(canvas.height - player.radius, player.y));
        }
    }
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    drawGrid();
    if (gameState === 'wave') updateGame(dt);
    drawSpawnIndicators();
    drawTowers();
    drawBombs();
    drawMonsters();
    drawProjectiles();
    drawBossProjectiles();
    drawMonsterProjectiles();
    drawMeleeAttacks();
    drawBossMeleeAttacks();
    drawVisualEffects();
    drawGroundEffects();
    drawSlowField();
    drawPlayer();
    if (gameState === 'wave' || gameState === 'shop' || gameState === 'statSelect') updateWeaponDisplay();
    requestAnimationFrame(gameLoop);
}

function drawGrid() { ctx.strokeStyle = 'rgba(100,100,150,0.1)'; ctx.lineWidth = 1; for (let x = 0; x < canvas.width; x += 50) { ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, canvas.height); ctx.stroke(); } for (let y = 0; y < canvas.height; y += 50) { ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(canvas.width, y); ctx.stroke(); } }
function drawBombs() { placedBombs.forEach(b => { if (!b.active) return; ctx.save(); ctx.translate(b.x, b.y); const t = b.detonateTime - Date.now(), p = Math.max(0, Math.min(1, t / 2000)), pulse = Math.sin(Date.now() * 0.01) * 0.2 + 0.8; ctx.shadowColor = '#F00'; ctx.shadowBlur = 20; ctx.strokeStyle = '#FFA500'; ctx.lineWidth = 3; ctx.beginPath(); ctx.arc(0, 0, b.radius * (1 + (1 - p)), 0, Math.PI * 2); ctx.stroke(); ctx.fillStyle = '#000'; ctx.beginPath(); ctx.arc(0, 0, b.radius * pulse, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#FFA500'; ctx.beginPath(); ctx.arc(0, -b.radius, 3, 0, Math.PI * 2); ctx.fill(); if (p < 0.2) { ctx.fillStyle = '#F00'; ctx.beginPath(); ctx.arc(0, -b.radius - 5, 2, 0, Math.PI * 2); ctx.fill(); } ctx.fillStyle = '#FFF'; ctx.font = 'bold 10px Arial'; ctx.textAlign = 'center'; ctx.fillText(`${Math.ceil(t / 1000)}s`, 0, b.radius + 15); ctx.restore(); }); }
function drawTowers() { playerTowers.landmines.active.forEach(m => { ctx.save(); ctx.translate(m.x, m.y); const pulse = Math.sin(Date.now() * 0.01) * 0.2 + 0.8; ctx.shadowColor = '#8B4513'; ctx.shadowBlur = 15; ctx.strokeStyle = '#F00'; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(0, 0, m.radius * pulse, 0, Math.PI * 2); ctx.stroke(); ctx.fillStyle = m.color; ctx.beginPath(); ctx.arc(0, 0, m.radius, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#FF4500'; ctx.beginPath(); ctx.arc(0, 0, m.radius * 0.5, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#FFF'; ctx.font = 'bold 12px Arial'; ctx.textAlign = 'center'; ctx.fillText('💣', 0, 0); ctx.restore(); }); drawHealingTowers(); }
function drawSpawnIndicators() { const ct = Date.now(); for (let i = spawnIndicators.length - 1; i >= 0; i--) { const ind = spawnIndicators[i]; const e = ct - ind.startTime, p = e / ind.timer; if (e > ind.timer) { spawnIndicators.splice(i, 1); continue; } const scale = 1 + Math.sin(p * Math.PI * 4) * 0.2, a = 1 - p * 0.5; ctx.save(); ctx.translate(ind.x, ind.y); if (ind.isBoss) { ctx.strokeStyle = `rgba(255,215,0,${a})`; ctx.lineWidth = 4; ctx.shadowColor = '#ffd700'; ctx.shadowBlur = 20 * a; ctx.rotate(e * 0.002); ctx.beginPath(); ctx.arc(0, 0, 40 * scale, 0, Math.PI * 2); ctx.stroke(); ctx.beginPath(); ctx.arc(0, 0, 25, 0, Math.PI * 2); ctx.stroke(); ctx.rotate(-e * 0.002); ctx.beginPath(); ctx.moveTo(-30, -30); ctx.lineTo(30, 30); ctx.moveTo(30, -30); ctx.lineTo(-30, 30); ctx.stroke(); } else { ctx.strokeStyle = `rgba(255,0,0,${a})`; ctx.lineWidth = 3; ctx.shadowColor = '#f00'; ctx.shadowBlur = 10 * a; ctx.beginPath(); ctx.arc(0, 0, 25 * scale, 0, Math.PI * 2); ctx.stroke(); ctx.beginPath(); ctx.moveTo(-15, -15); ctx.lineTo(15, 15); ctx.moveTo(15, -15); ctx.lineTo(-15, 15); ctx.stroke(); } ctx.restore(); } }
function drawSlowField() { if (bossAbilities.slowField && bossAbilities.slowField.active) { const boss = monsters.find(m => m.isBoss && wave === 30); if (boss) { ctx.save(); ctx.translate(boss.x, boss.y); const pulse = Math.sin(Date.now() * 0.005) * 0.1 + 0.9; ctx.fillStyle = `rgba(100,100,255,0.3)`; ctx.shadowColor = '#6464ff'; ctx.shadowBlur = 30; ctx.beginPath(); ctx.arc(0, 0, bossAbilities.slowField.radius * pulse, 0, Math.PI * 2); ctx.fill(); ctx.strokeStyle = `rgba(200,200,255,0.3)`; ctx.lineWidth = 3; ctx.beginPath(); ctx.arc(0, 0, bossAbilities.slowField.radius * 0.7, 0, Math.PI * 2); ctx.stroke(); ctx.fillStyle = 'white'; ctx.font = 'bold 16px Arial'; ctx.textAlign = 'center'; ctx.fillText('SLOW FIELD', 0, -bossAbilities.slowField.radius - 20); if (player.inSlowField && player.slowFieldTicks > 0) { ctx.fillStyle = 'rgba(255,100,100,0.9)'; ctx.font = 'bold 14px Arial'; ctx.fillText(`Speed Lost: ${player.slowFieldTicks}`, 0, bossAbilities.slowField.radius + 30); } ctx.restore(); } } }
function drawProjectiles() { const ct = Date.now(); player.projectiles.forEach(p => { ctx.save(); if (p.isBoomerang) drawBoomerangProjectile(ctx, p, ct); else if (p.weaponId === 'shotgun') drawShotgunPellet(ctx, p, ct); else if (p.weaponId === 'laser') drawLaserProjectile(ctx, p, ct); else if (p.weaponId === 'machinegun') drawMachinegunProjectile(ctx, p, ct); else if (p.animation === 'knife') drawThrowingKnife(ctx, p, ct); else if (p.weaponId === 'sniper') drawSniperProjectile(ctx, p, ct); else if (p.weaponId === 'crossbow') drawCrossbowProjectile(ctx, p, ct); else { ctx.shadowColor = p.color; ctx.shadowBlur = 15; ctx.fillStyle = p.color; ctx.beginPath(); ctx.arc(p.x, p.y, p.size || 4, 0, Math.PI * 2); ctx.fill(); ctx.shadowBlur = 0; ctx.strokeStyle = p.color; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(p.x - Math.cos(p.angle) * 10, p.y - Math.sin(p.angle) * 10); ctx.lineTo(p.x, p.y); ctx.stroke(); } ctx.restore(); }); }
function drawSniperProjectile(ctx, p, ct) { ctx.save(); ctx.translate(p.x, p.y); ctx.shadowColor = '#FF4500'; ctx.shadowBlur = 20; ctx.fillStyle = '#FFD700'; ctx.beginPath(); ctx.arc(0, 0, 5, 0, Math.PI * 2); ctx.fill(); ctx.strokeStyle = '#FF4500'; ctx.lineWidth = 3; ctx.beginPath(); ctx.moveTo(-Math.cos(p.angle) * 15, -Math.sin(p.angle) * 15); ctx.lineTo(0, 0); ctx.stroke(); const age = ct - p.startTime; if (age < 100) { ctx.fillStyle = `rgba(255,200,0,${1 - age/100})`; ctx.shadowBlur = 30; ctx.beginPath(); ctx.arc(-Math.cos(p.angle) * 10, -Math.sin(p.angle) * 10, 8, 0, Math.PI * 2); ctx.fill(); } ctx.restore(); }
function drawCrossbowProjectile(ctx, p, ct) { ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.angle); ctx.shadowColor = '#8B4513'; ctx.shadowBlur = 15; ctx.fillStyle = '#8B4513'; ctx.fillRect(-15, -2, 30, 4); ctx.fillStyle = '#C0C0C0'; ctx.beginPath(); ctx.moveTo(15, -3); ctx.lineTo(25, 0); ctx.lineTo(15, 3); ctx.closePath(); ctx.fill(); ctx.fillStyle = '#F00'; ctx.beginPath(); ctx.moveTo(-15, -4); ctx.lineTo(-25, -8); ctx.lineTo(-15, -2); ctx.closePath(); ctx.fill(); ctx.beginPath(); ctx.moveTo(-15, 4); ctx.lineTo(-25, 8); ctx.lineTo(-15, 2); ctx.closePath(); ctx.fill(); if (p.pierceCount && p.pierceCount < 3) { ctx.strokeStyle = '#FFD700'; ctx.lineWidth = 2; ctx.shadowColor = '#FFD700'; ctx.beginPath(); ctx.arc(0, 0, 8, 0, Math.PI * 2); ctx.stroke(); } ctx.restore(); }
function drawThrowingKnife(ctx, p, ct) { p.rotation = (p.rotation || 0) + (p.spinSpeed || 0); ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.rotation); ctx.shadowColor = '#C0C0C0'; ctx.shadowBlur = 15; ctx.fillStyle = '#C0C0C0'; ctx.strokeStyle = '#808080'; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(0, -p.size); ctx.lineTo(p.size, 0); ctx.lineTo(0, p.size); ctx.lineTo(-p.size, 0); ctx.closePath(); ctx.fill(); ctx.stroke(); ctx.fillStyle = '#8B4513'; ctx.fillRect(-p.size * 0.3, -p.size * 0.8, p.size * 0.6, p.size * 1.6); ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.beginPath(); ctx.arc(-p.size * 0.2, -p.size * 0.5, 1, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }
function drawMonsterProjectiles() { monsterProjectiles.forEach(p => { ctx.save(); ctx.translate(p.x, p.y); ctx.shadowColor = p.color; ctx.shadowBlur = 15; ctx.fillStyle = p.color; ctx.beginPath(); ctx.arc(0, 0, 5, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#FFF'; ctx.beginPath(); ctx.arc(0, 0, 2, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }); }
function drawBossProjectiles() { const ct = Date.now(); bossProjectiles.forEach(p => { const age = ct - p.startTime, a = Math.min(1, 1 - age / p.lifetime); ctx.save(); ctx.translate(p.x, p.y); ctx.shadowColor = p.color; ctx.shadowBlur = 15 * a; ctx.fillStyle = p.color; ctx.globalAlpha = a * 0.7; ctx.beginPath(); ctx.arc(0, 0, p.radius + 2, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#FFF'; ctx.globalAlpha = a; ctx.beginPath(); ctx.arc(0, 0, p.radius, 0, Math.PI * 2); ctx.fill(); if (p.isHoming) { ctx.strokeStyle = '#FF0'; ctx.lineWidth = 2; ctx.globalAlpha = a * 0.8; ctx.beginPath(); ctx.arc(0, 0, p.radius + 5, 0, Math.PI * 2); ctx.stroke(); for (let i = 0; i < 3; i++) { ctx.beginPath(); ctx.moveTo(Math.cos(i * Math.PI * 2 / 3) * (p.radius + 8), Math.sin(i * Math.PI * 2 / 3) * (p.radius + 8)); ctx.lineTo(Math.cos((i + 0.5) * Math.PI * 2 / 3) * (p.radius + 3), Math.sin((i + 0.5) * Math.PI * 2 / 3) * (p.radius + 3)); ctx.stroke(); } } ctx.restore(); }); }
function drawBoomerangProjectile(ctx, p, ct) { p.rotation = (p.rotation || 0) + 0.1; if (boomerangImage.complete && boomerangImage.naturalHeight) { ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.rotation); ctx.shadowColor = '#8B4513'; ctx.shadowBlur = 15; ctx.drawImage(boomerangImage, -20, -20, 40, 40); ctx.restore(); if (p.state === 'returning') { ctx.save(); ctx.globalAlpha = 0.3; for (let i = 1; i <= 3; i++) { const tx = p.x - Math.cos(p.angle) * i * 5, ty = p.y - Math.sin(p.angle) * i * 5; ctx.save(); ctx.translate(tx, ty); ctx.rotate(p.rotation - i * 0.1); ctx.drawImage(boomerangImage, -15, -15, 30, 30); ctx.restore(); } ctx.restore(); } } else { ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.rotation); ctx.shadowColor = 'rgba(139,69,19,0.5)'; ctx.shadowBlur = 15; ctx.fillStyle = '#8B4513'; ctx.strokeStyle = '#654321'; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(20, -10); ctx.lineTo(25, 0); ctx.lineTo(20, 10); ctx.lineTo(0, 5); ctx.closePath(); ctx.fill(); ctx.stroke(); if (p.state === 'returning') { ctx.strokeStyle = '#FFD700'; ctx.lineWidth = 2; ctx.shadowColor = '#FFD700'; ctx.shadowBlur = 10; ctx.stroke(); } ctx.restore(); } }
function drawShotgunPellet(ctx, p, ct) { ctx.shadowColor = p.color; ctx.shadowBlur = 10; ctx.fillStyle = p.color; ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI * 2); ctx.fill(); ctx.shadowBlur = 5; ctx.fillStyle = 'rgba(255,255,255,0.5)'; ctx.beginPath(); ctx.arc(p.x - Math.cos(p.angle) * 5, p.y - Math.sin(p.angle) * 5, 2, 0, Math.PI * 2); ctx.fill(); }
function drawLaserProjectile(ctx, p, ct) { const pulse = Math.sin(ct * 0.02) * 2; ctx.shadowColor = '#0FF'; ctx.shadowBlur = 20; ctx.strokeStyle = '#0FF'; ctx.lineWidth = 4 + pulse; ctx.beginPath(); ctx.moveTo(p.x - Math.cos(p.angle) * 10, p.y - Math.sin(p.angle) * 10); ctx.lineTo(p.x, p.y); ctx.stroke(); ctx.strokeStyle = '#FFF'; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(p.x - Math.cos(p.angle) * 10, p.y - Math.sin(p.angle) * 10); ctx.lineTo(p.x, p.y); ctx.stroke(); ctx.fillStyle = 'rgba(0,255,255,0.3)'; ctx.shadowBlur = 30; ctx.beginPath(); ctx.arc(p.x, p.y, 6, 0, Math.PI * 2); ctx.fill(); }
function drawMachinegunProjectile(ctx, p, ct) { ctx.shadowColor = '#FFD700'; ctx.shadowBlur = 15; ctx.fillStyle = '#FFD700'; ctx.beginPath(); ctx.arc(p.x, p.y, 3, 0, Math.PI * 2); ctx.fill(); for (let i = 1; i <= 3; i++) { ctx.fillStyle = `rgba(255,215,0,${0.3 - i * 0.1})`; ctx.beginPath(); ctx.arc(p.x - Math.cos(p.angle) * i * 8, p.y - Math.sin(p.angle) * i * 8, 2, 0, Math.PI * 2); ctx.fill(); } }
function drawMeleeAttacks() { const ct = Date.now(); player.meleeAttacks.forEach(a => { const p = (ct - a.startTime) / a.duration; if (p < 0 || p > 1) return; ctx.save(); ctx.translate(a.x, a.y); const d = a.radius * (p * 1.2), alpha = 1 - p * 0.7; switch(a.weaponId) { case 'sword': drawSword(ctx, a, a.angle, p, d, alpha); break; case 'axe': drawAxe(ctx, a, a.angle, p, d, alpha); break; case 'dagger': drawDagger(ctx, a, a.angle, p, d, alpha); break; case 'hammer': drawHammer(ctx, a, a.angle, p, d, alpha); break; case 'spear': drawTrident(ctx, a, a.angle, p, d, alpha); break; case 'dual_daggers': drawDualDaggers(ctx, a, a.angle, p, d, alpha); break; default: drawDefaultMelee(ctx, a, a.angle, p, d, alpha); } ctx.restore(); }); }
function drawDualDaggers(ctx, a, angle, p, d, alpha) { ctx.save(); ctx.rotate(angle - 0.2); ctx.translate(d * 0.8, 0); ctx.shadowColor = 'rgba(70,130,180,0.5)'; ctx.shadowBlur = 10 * alpha; ctx.fillStyle = a.bladeColor || '#4682B4'; ctx.beginPath(); ctx.moveTo(0, -3); ctx.lineTo(30, -1); ctx.lineTo(30, 1); ctx.lineTo(0, 3); ctx.closePath(); ctx.fill(); ctx.fillStyle = a.hiltColor || '#2F4F4F'; ctx.fillRect(-5, -4, 8, 8); ctx.fillStyle = a.sparkleColor || '#0FF'; ctx.globalAlpha = alpha * 0.3; ctx.beginPath(); ctx.arc(30, 0, 5, 0, Math.PI * 2); ctx.fill(); ctx.restore(); ctx.save(); ctx.rotate(angle + 0.2); ctx.translate(d * 0.8, 0); ctx.shadowColor = 'rgba(70,130,180,0.5)'; ctx.shadowBlur = 10 * alpha; ctx.fillStyle = a.bladeColor || '#4682B4'; ctx.beginPath(); ctx.moveTo(0, -3); ctx.lineTo(30, -1); ctx.lineTo(30, 1); ctx.lineTo(0, 3); ctx.closePath(); ctx.fill(); ctx.fillStyle = a.hiltColor || '#2F4F4F'; ctx.fillRect(-5, -4, 8, 8); ctx.fillStyle = a.sparkleColor || '#0FF'; ctx.globalAlpha = alpha * 0.3; ctx.beginPath(); ctx.arc(30, 0, 5, 0, Math.PI * 2); ctx.fill(); ctx.restore(); if (p < 0.5) { ctx.save(); ctx.rotate(angle); ctx.strokeStyle = `rgba(255,255,255,${alpha * 0.3})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(40, 0); ctx.stroke(); ctx.restore(); } }
function drawBossMeleeAttacks() { if (!bossAbilities.bossWeapon || !bossAbilities.bossWeaponAttack) return; const ct = Date.now(); const a = bossAbilities.bossWeaponAttack; const p = (ct - a.startTime) / a.duration; if (p < 0 || p > 1) { bossAbilities.bossWeaponAttack = null; return; } ctx.save(); ctx.translate(a.x, a.y); const d = a.radius * (p * 1.2), alpha = 1 - p * 0.7; if (wave === 10) drawBossDagger(ctx, a, a.angle, p, d, alpha); else if (wave === 20) drawBossHammer(ctx, a, a.angle, p, d, alpha); else if (wave === 30) drawBossScythe(ctx, a, a.angle, p, d, alpha); ctx.restore(); }
function drawBossDagger(ctx, a, angle, p, d, alpha) { const stab = Math.min(p * 2, 1); const sd = d * 1.5; ctx.rotate(angle); ctx.translate(sd, 0); ctx.shadowColor = 'rgba(139,0,0,0.7)'; ctx.shadowBlur = 20 * alpha; ctx.save(); const grad = ctx.createLinearGradient(0, -5, 60, -5); grad.addColorStop(0, '#8B0000'); grad.addColorStop(1, '#F44'); ctx.fillStyle = grad; ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(60, -3); ctx.lineTo(60, 3); ctx.lineTo(0, 5); ctx.closePath(); ctx.fill(); ctx.strokeStyle = `rgba(255,255,255,${alpha})`; ctx.lineWidth = 2; ctx.beginPath(); ctx.moveTo(0, -5); ctx.lineTo(60, -3); ctx.moveTo(0, 5); ctx.lineTo(60, 3); ctx.stroke(); ctx.restore(); if (p > 0.7) { ctx.save(); ctx.translate(60, 0); ctx.fillStyle = `rgba(255,0,0,${alpha})`; ctx.shadowColor = 'rgba(255,0,0,0.7)'; ctx.beginPath(); ctx.arc(0, 0, 8 * (1 - p), 0, Math.PI * 2); ctx.fill(); ctx.restore(); } ctx.save(); ctx.fillStyle = '#4A0404'; ctx.fillRect(-12, -6, 20, 12); ctx.fillStyle = '#8B0000'; ctx.beginPath(); ctx.arc(-18, 0, 8, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }
function drawBossHammer(ctx, a, angle, p, d, alpha) { ctx.rotate(angle); const lift = Math.sin(p * Math.PI) * 50; const smash = p < 0.3 ? -lift : (p > 0.6 ? (p - 0.6) * 60 : 0); ctx.translate(30, -50 + lift - smash); ctx.shadowColor = 'rgba(105,105,105,0.7)'; ctx.shadowBlur = 30 * alpha; ctx.save(); ctx.fillStyle = '#8B4513'; ctx.fillRect(-5, 0, 10, 80); ctx.restore(); ctx.save(); ctx.translate(0, -25); ctx.fillStyle = '#696969'; ctx.fillRect(-25, -25, 50, 35); ctx.fillStyle = '#808080'; ctx.fillRect(-30, -25, 10, 35); ctx.fillRect(20, -25, 10, 35); ctx.fillStyle = '#A9A9A9'; ctx.fillRect(-25, -35, 50, 10); ctx.restore(); if (p > 0.5 && p < 0.8) { ctx.save(); ctx.translate(0, 0); ctx.rotate(0); const sp = (p - 0.5) * 3.33; ctx.strokeStyle = `rgba(255,69,0,${alpha * (1 - sp)})`; ctx.lineWidth = 5; ctx.beginPath(); ctx.arc(0, 50, a.radius * sp, 0, Math.PI * 2); ctx.stroke(); ctx.restore(); } }
