function drawGroundEffects() { groundFire.forEach(f => { const p = (Date.now() - f.startTime) / f.duration; if (p > 1) return; ctx.save(); ctx.globalAlpha = 1 - p * 0.5; ctx.fillStyle = '#FF4500'; ctx.shadowColor = '#FF4500'; ctx.shadowBlur = 15; ctx.beginPath(); ctx.arc(f.x, f.y, f.radius, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#FFD700'; ctx.shadowBlur = 20; ctx.beginPath(); ctx.arc(f.x, f.y, f.radius * 0.6, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }); poisonClouds.forEach(c => { const p = (Date.now() - c.startTime) / c.duration; if (p > 1) return; ctx.save(); ctx.globalAlpha = 0.4 * (1 - p); ctx.fillStyle = '#32CD32'; ctx.shadowColor = '#32CD32'; ctx.shadowBlur = 20; ctx.beginPath(); ctx.arc(c.x, c.y, c.radius, 0, Math.PI * 2); ctx.fill(); ctx.restore(); }); activeTraps.forEach(t => { if (!t.active) return; ctx.save(); ctx.fillStyle = '#F00'; ctx.shadowColor = '#F00'; ctx.shadowBlur = 10; ctx.beginPath(); ctx.arc(t.x, t.y, 15, 0, Math.PI * 2); ctx.fill(); ctx.strokeStyle = '#FFF'; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(t.x, t.y, 20, 0, Math.PI * 2); ctx.stroke(); ctx.restore(); }); }
function drawPlayer() { ctx.save(); ctx.translate(player.x, player.y); let mx = 0, my = 0; if (keys.w || keys.up) my -= 1; if (keys.s || keys.down) my += 1; if (keys.a || keys.left) mx -= 1; if (keys.d || keys.right) mx += 1; if (joystickActive) { const str = Math.min(1, Math.hypot(joystickCurrentX, joystickCurrentY) / joystickMaxDistance); mx += (joystickCurrentX / joystickMaxDistance) * str; my += (joystickCurrentY / joystickMaxDistance) * str; } const moving = mx !== 0 || my !== 0; let facing = player.lastFacingAngle || 0; if (moving) { facing = Math.atan2(my, mx); player.lastFacingAngle = facing; } else facing = Math.atan2(mouseY - player.y, mouseX - player.x); player.facingAngle = facing; ctx.shadowColor = 'rgba(255,107,107,0.5)'; ctx.shadowBlur = 15; ctx.fillStyle = player.color; ctx.beginPath(); ctx.arc(0, 0, player.radius, 0, Math.PI * 2); ctx.fill(); ctx.shadowBlur = 0; ctx.strokeStyle = '#FFF'; ctx.lineWidth = 3; ctx.beginPath(); ctx.arc(0, 0, player.radius, 0, Math.PI * 2); ctx.stroke(); ctx.save(); ctx.rotate(facing); ctx.fillStyle = '#FFF'; ctx.shadowBlur = 5; ctx.shadowColor = '#FFF'; ctx.beginPath(); ctx.arc(8, -5, 4, 0, Math.PI * 2); ctx.fill(); ctx.beginPath(); ctx.arc(8, 5, 4, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#000'; ctx.shadowBlur = 0; let px = 8, py = -5; if (moving) { px += Math.cos(facing) * 1.5; py += Math.sin(facing) * 1.5; } else { const ma = Math.atan2(mouseY - player.y, mouseX - player.x) - facing; px += Math.cos(ma) * 1.5; py += Math.sin(ma) * 1.5; } ctx.beginPath(); ctx.arc(px, py - 5, 2, 0, Math.PI * 2); ctx.fill(); ctx.beginPath(); ctx.arc(px, py + 5, 2, 0, Math.PI * 2); ctx.fill(); ctx.strokeStyle = '#000'; ctx.lineWidth = 2; if (moving) { ctx.beginPath(); ctx.moveTo(12, -2); ctx.lineTo(18, 0); ctx.lineTo(12, 2); ctx.stroke(); } else { ctx.beginPath(); ctx.moveTo(12, -1); ctx.lineTo(18, 0); ctx.moveTo(12, 1); ctx.lineTo(18, 0); ctx.stroke(); } ctx.restore(); ctx.save(); ctx.rotate(facing); ctx.strokeStyle = '#fc0'; ctx.lineWidth = 3; ctx.shadowColor = '#fc0'; ctx.shadowBlur = 10; ctx.beginPath(); ctx.moveTo(player.radius + 2, 0); ctx.lineTo(player.radius + 15, 0); ctx.stroke(); ctx.fillStyle = '#fc0'; ctx.shadowBlur = 15; ctx.beginPath(); ctx.arc(player.radius + 18, 0, 4, 0, Math.PI * 2); ctx.fill(); ctx.restore(); if (player.firstHitReduction && player.firstHitActive) { ctx.shadowColor = '#0FF'; ctx.shadowBlur = 20; ctx.strokeStyle = '#0FF'; ctx.lineWidth = 3; ctx.beginPath(); ctx.arc(0, 0, player.radius + 10, 0, Math.PI * 2); ctx.stroke(); } if (player.bloodContract) { ctx.shadowColor = '#8B0000'; ctx.shadowBlur = 20; ctx.strokeStyle = '#8B0000'; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(0, 0, player.radius + 5 + Math.sin(Date.now() * 0.005) * 2, 0, Math.PI * 2); ctx.stroke(); ctx.fillStyle = '#8B0000'; ctx.font = 'bold 12px Arial'; ctx.textAlign = 'center'; ctx.fillText(`${player.bloodContractStacks}`, 0, -player.radius - 10); } if (activeBuffs.rage.active) { ctx.shadowColor = '#F00'; ctx.shadowBlur = 30; ctx.strokeStyle = '#F00'; ctx.lineWidth = 4; ctx.beginPath(); ctx.arc(0, 0, player.radius + 10 + Math.sin(Date.now() * 0.02) * 5, 0, Math.PI * 2); ctx.stroke(); } if (player.inSlowField) { ctx.shadowColor = '#6464ff'; ctx.shadowBlur = 15; ctx.strokeStyle = '#6464ff'; ctx.lineWidth = 3; ctx.beginPath(); ctx.arc(0, 0, player.radius + 8 + Math.sin(Date.now() * 0.01) * 3, 0, Math.PI * 2); ctx.stroke(); if (player.slowFieldTicks > 0) { ctx.fillStyle = 'rgba(255,100,100,0.9)'; ctx.font = 'bold 14px Arial'; ctx.textAlign = 'center'; ctx.shadowColor = '#f00'; ctx.shadowBlur = 10; ctx.fillText(`-${player.slowFieldTicks} SPD`, 0, -player.radius - 20); } } ctx.restore(); }

function updateGame(dt) {
    const ct = Date.now();
    checkLandmineTriggers();
    updateHealingTowers(ct);
    if (bossAbilities.slowField && bossAbilities.slowField.active) {
        const boss = monsters.find(m => m.isBoss && wave === 30);
        if (boss) {
            const inField = Math.hypot(player.x - boss.x, player.y - boss.y) < bossAbilities.slowField.radius;
            const was = player.inSlowField;
            player.inSlowField = inField;
            if (inField) {
                player.speed = (player.baseSpeed * player.speedMultiplier) * 0.5;
                if (ct - player.lastSlowFieldTick >= 1000) {
                    player.baseSpeed = Math.max(1, player.baseSpeed - 1);
                    player.speed = (player.baseSpeed * player.speedMultiplier) * 0.5;
                    player.slowFieldTicks++;
                    player.lastSlowFieldTick = ct;
                    createDamageIndicator(player.x, player.y, 1, false);
                    queueMessage("Speed decreased by 1!");
                }
            } else if (was) player.speed = player.baseSpeed * player.speedMultiplier;
        }
    }
    if (wave === 20 && !bossAbilities.enraged) {
        const boss = monsters.find(m => m.isBoss);
        if (boss && boss.health <= boss.maxHealth / 2) {
            bossAbilities.enraged = true;
            boss.attackCooldown = 800;
            boss.color = '#f44';
            boss.speed = boss.originalSpeed * 1.3;
            queueMessage("BOSS ENRAGED - ATTACK SPEED AND MOVEMENT INCREASED!");
        }
    }
    if (wave === 30 && bossAbilities.bossWeapon) {
        const boss = monsters.find(m => m.isBoss);
        if (boss && !bossAbilities.bossDash && ct - bossAbilities.bossDashCooldown > 3000) {
            const dx = player.x - boss.x, dy = player.y - boss.y, d = Math.hypot(dx, dy);
            const dir = { x: dx / d, y: dy / d };
            bossAbilities.bossDash = true;
            bossAbilities.bossDashDirection = dir;
            bossAbilities.bossDashStart = ct;
            bossAbilities.bossDashDistance = 0;
            bossAbilities.bossDashTarget = { x: boss.x + dir.x * BOSS_WEAPONS.SCYTHE.dashRange, y: boss.y + dir.y * BOSS_WEAPONS.SCYTHE.dashRange };
            setTimeout(() => { bossAbilities.bossDash = false; bossAbilities.bossDashCooldown = ct; bossAbilities.bossDashDistance = 0; }, 500);
        }
        if (bossAbilities.bossDash && bossAbilities.bossDashDirection) {
            const spd = BOSS_WEAPONS.SCYTHE.dashSpeed;
            boss.x += bossAbilities.bossDashDirection.x * spd;
            boss.y += bossAbilities.bossDashDirection.y * spd;
            bossAbilities.bossDashDistance += spd;
            if (!bossAbilities.bossWeaponAttack && bossAbilities.bossDashDistance < 100) {
                const angle = Math.atan2(player.y - boss.y, player.x - boss.x);
                bossAbilities.bossWeaponAttack = { type: 'melee', x: boss.x, y: boss.y, radius: BOSS_WEAPONS.SCYTHE.range, damage: BOSS_WEAPONS.SCYTHE.baseDamage, color: BOSS_WEAPONS.SCYTHE.swingColor, startTime: ct, duration: 300, swingAngle: BOSS_WEAPONS.SCYTHE.swingAngle, meleeType: BOSS_WEAPONS.SCYTHE.meleeType, angle, lifeSteal: BOSS_WEAPONS.SCYTHE.lifeSteal };
            }
            if (Math.hypot(player.x - boss.x, player.y - boss.y) < boss.radius + player.radius) {
                const dmg = BOSS_WEAPONS.SCYTHE.baseDamage * 0.5;
                player.health -= dmg;
                createDamageIndicator(player.x, player.y, dmg, true);
                const heal = dmg * BOSS_WEAPONS.SCYTHE.lifeSteal;
                boss.health = Math.min(boss.maxHealth, boss.health + heal);
                createHealthPopup(boss.x, boss.y, Math.floor(heal));
            }
        }
    }
    if (bossAbilities.bossWeapon && wave !== 30) {
        const boss = monsters.find(m => m.isBoss);
        if (boss && Math.hypot(player.x - boss.x, player.y - boss.y) <= bossAbilities.bossWeapon.range && ct - (bossAbilities.bossWeapon.lastAttack || 0) > 2000) {
            const angle = Math.atan2(player.y - boss.y, player.x - boss.x);
            bossAbilities.bossWeaponAttack = { type: 'melee', x: boss.x, y: boss.y, radius: bossAbilities.bossWeapon.range, damage: bossAbilities.bossWeapon.baseDamage, color: bossAbilities.bossWeapon.swingColor, startTime: ct, duration: 300, swingAngle: bossAbilities.bossWeapon.swingAngle, meleeType: bossAbilities.bossWeapon.meleeType, angle, pierceCount: bossAbilities.bossWeapon.pierceCount || 1 };
            bossAbilities.bossWeapon.lastAttack = ct;
        }
    }
    if ((player.healthRegen > 0 || player.healthRegenPercent > 0) && ct - player.lastRegen >= 1000) {
        let regen = 0;
        if (player.healthRegen > 0) regen += player.healthRegen;
        if (player.healthRegenPercent > 0) regen += Math.floor(player.maxHealth * player.healthRegenPercent);
        if (regen > 0 && player.health < player.maxHealth) applyHealing(Math.max(1, regen));
        player.lastRegen = ct;
    }
    updateWeapons();
    updateProjectiles();
    updateMonsterProjectiles(ct);
    updateBossProjectiles(ct);
    updateMeleeAttacks();
    updateMonsters(ct);
    updateGroundEffects(ct);
    updateVisualEffects();
    if (waveActive && monsters.length === 0 && spawnIndicators.length === 0) { wave++; endWave(); }
    updateUI();
}
function updateWeapons() { const ct = Date.now(); weaponTargets.clear(); player.weapons.forEach(w => { if (!w || !monsters.length) return; const orig = w.attackSpeed; w.attackSpeed = orig * player.attackSpeedMultiplier; const can = w.canAttack(ct); w.attackSpeed = orig; if (can) { const target = selectTargetForWeapon(w, ct); if (target) { weaponTargets.set(w.id, target); const atk = w.attack(player.x, player.y, target.x, target.y); if (w.id === 'shotgun') player.projectiles.push(...atk); else if (w.type === 'ranged') player.projectiles.push(atk); else { player.meleeAttacks.push(atk); if (w.dualStrike) player.meleeAttacks.push({ ...atk, angle: atk.angle + 0.2 }); } attackedMonsters.add(target); } } }); }
function shootGunnerProjectile(g) { const ct = Date.now(), a = Math.atan2(player.y - g.y, player.x - g.x); monsterProjectiles.push({ x: g.x, y: g.y, vx: Math.cos(a) * MONSTER_TYPES.GUNNER.projectileSpeed, vy: Math.sin(a) * MONSTER_TYPES.GUNNER.projectileSpeed, damage: MONSTER_TYPES.GUNNER.projectileDamage, radius: 5, color: MONSTER_TYPES.GUNNER.projectileColor, startTime: ct, lifetime: 3000 }); }
function updateMonsterProjectiles(ct) { for (let i = monsterProjectiles.length - 1; i >= 0; i--) { const p = monsterProjectiles[i]; p.x += p.vx; p.y += p.vy; if (ct - p.startTime > p.lifetime) { monsterProjectiles.splice(i, 1); continue; } if (Math.hypot(player.x - p.x, player.y - p.y) < player.radius + p.radius) { let dmg = p.damage; if (player.firstHitActive) { dmg *= 0.5; player.firstHitActive = false; queueMessage("Runic Plate absorbed 50% damage!"); } if (player.damageReduction > 0) dmg *= (1 - player.damageReduction); player.health -= dmg; createDamageIndicator(player.x, player.y, Math.floor(dmg), false); if (player.health <= 0) gameOver(); monsterProjectiles.splice(i, 1); } if (p.x < -50 || p.x > canvas.width + 50 || p.y < -50 || p.y > canvas.height + 50) monsterProjectiles.splice(i, 1); } }
function shootBossProjectiles(boss) { const ct = Date.now(), base = Math.atan2(player.y - boss.y, player.x - boss.x); if (wave === 10) { for (let i = -2; i <= 2; i++) { if (i === 0) continue; const a = base + i * 0.35; bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(a) * 6, vy: Math.sin(a) * 6, damage: 10, radius: 5, color: '#f88', startTime: ct, lifetime: 2500, isHoming: false }); } bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(base) * 5, vy: Math.sin(base) * 5, damage: 12, radius: 6, color: '#f44', startTime: ct, lifetime: 4000, isHoming: true, homingStrength: 0.03, target: { x: player.x, y: player.y } }); } else if (wave === 20) { for (let i = -2; i <= 2; i++) { if (i === 0) continue; const a = base + i * 0.4; bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(a) * 5, vy: Math.sin(a) * 5, damage: 12, radius: 6, color: '#f44', startTime: ct, lifetime: 3000, isHoming: false }); } for (let h = -1; h <= 1; h++) { if (h === 0) continue; const a = base + h * 0.2; bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(a) * 4.5, vy: Math.sin(a) * 4.5, damage: 15, radius: 7, color: '#f60', startTime: ct, lifetime: 4000, isHoming: true, homingStrength: 0.04, target: { x: player.x, y: player.y } }); } } else if (wave === 30) { for (let i = -3; i <= 3; i++) { if (i === 0) continue; const a = base + i * 0.3; bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(a) * 5.5, vy: Math.sin(a) * 5.5, damage: 14, radius: 6, color: '#f44', startTime: ct, lifetime: 3000, isHoming: false }); } for (let h = -1; h <= 1; h++) { const a = base + h * 0.25; bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(a) * 5, vy: Math.sin(a) * 5, damage: 18, radius: 8, color: '#f00', startTime: ct, lifetime: 4500, isHoming: true, homingStrength: 0.05, target: { x: player.x, y: player.y } }); } } else { for (let i = -2; i <= 2; i++) { const a = base + i * 0.25; bossProjectiles.push({ x: boss.x, y: boss.y, vx: Math.cos(a) * 5, vy: Math.sin(a) * 5, damage: 15, radius: 8, color: '#f44', startTime: ct, lifetime: 3000, isHoming: false }); } } }
function updateBossProjectiles(ct) { for (let i = bossProjectiles.length - 1; i >= 0; i--) { const p = bossProjectiles[i]; if (p.isHoming) { p.target = { x: player.x, y: player.y }; const dx = p.target.x - p.x, dy = p.target.y - p.y, d = Math.hypot(dx, dy); if (d > 0.01) { const cur = Math.atan2(p.vy, p.vx), tar = Math.atan2(dy, dx); let diff = tar - cur; while (diff > Math.PI) diff -= Math.PI * 2; while (diff < -Math.PI) diff += Math.PI * 2; const na = cur + Math.min(p.homingStrength, Math.abs(diff)) * Math.sign(diff); const spd = Math.hypot(p.vx, p.vy); p.vx = Math.cos(na) * spd; p.vy = Math.sin(na) * spd; } } p.x += p.vx; p.y += p.vy; if (ct - p.startTime > p.lifetime) { bossProjectiles.splice(i, 1); continue; } if (Math.hypot(player.x - p.x, player.y - p.y) < player.radius + p.radius) { let dmg = p.damage; if (player.firstHitActive) { dmg *= 0.5; player.firstHitActive = false; queueMessage("Runic Plate absorbed 50% damage!"); } if (player.damageReduction > 0) dmg *= (1 - player.damageReduction); player.health -= dmg; createDamageIndicator(player.x, player.y, Math.floor(dmg), true); if (player.health <= 0) gameOver(); bossProjectiles.splice(i, 1); } if (p.x < -50 || p.x > canvas.width + 50 || p.y < -50 || p.y > canvas.height + 50) bossProjectiles.splice(i, 1); } }
function updateProjectiles() { const ct = Date.now(); for (let i = player.projectiles.length - 1; i >= 0; i--) { const p = player.projectiles[i]; if (!p.startX) { p.startX = p.x; p.startY = p.y; p.startTime = ct; } if (p.isBoomerang) { if (p.state === 'outgoing') { p.x += Math.cos(p.angle) * p.speed; p.y += Math.sin(p.angle) * p.speed; p.distanceTraveled = Math.hypot(p.x - p.startX, p.y - p.startY); if (p.distanceTraveled >= p.range / 2) p.state = 'returning'; } else { const dx = player.x - p.x, dy = player.y - p.y; if (Math.hypot(dx, dy) < 10) { player.projectiles.splice(i, 1); continue; } const a = Math.atan2(dy, dx); p.x += Math.cos(a) * p.returnSpeed; p.y += Math.sin(a) * p.returnSpeed; p.angle = a; } p.rotation = (p.rotation || 0) + 0.2; } else { p.x += Math.cos(p.angle) * p.speed; p.y += Math.sin(p.angle) * p.speed; if (Math.hypot(p.x - player.x, p.y - player.y) > p.range) { player.projectiles.splice(i, 1); continue; } } if (p.bounceCount > 0 && p.targetsHit) { let best = null, bestD = Infinity; monsters.forEach(m => { if (p.targetsHit.includes(m)) return; const d = Math.hypot(p.x - m.x, p.y - m.y); if (d < bestD && d < p.bounceRange) { bestD = d; best = m; } }); if (best) { p.angle = Math.atan2(best.y - p.y, best.x - p.x); p.targetsHit.push(best); p.bounceCount--; continue; } } if (p.weaponId === 'crossbow' && p.pierceCount > 0) { if (!p.piercedEnemies) p.piercedEnemies = []; for (let j = monsters.length - 1; j >= 0; j--) { const m = monsters[j]; if (p.piercedEnemies.includes(m)) continue; if (Math.hypot(p.x - m.x, p.y - m.y) < 8 + m.radius) { let dmg = p.damage, crit = false; if (Math.random() < player.criticalChance) { dmg *= 2; crit = true; } dmg = Math.floor(dmg * player.damageMultiplier); m.health -= dmg; if (p.weaponRef && p.weaponRef.isThrowable) p.weaponRef.trackKnifeHit(m); createDamageIndicator(m.x, m.y, dmg, crit); p.piercedEnemies.push(m); p.pierceCount--; if (player.lifeSteal > 0) applyHealing(dmg * player.lifeSteal); if (m.isBoss && m.lifeSteal) { const bh = Math.floor(dmg * m.lifeSteal); if (bh > 0) { m.health = Math.min(m.maxHealth, m.health + bh); createHealthPopup(m.x, m.y, bh); } } if (m.health <= 0) handleMonsterDeath(m, j); if (p.pierceCount <= 0) { player.projectiles.splice(i, 1); break; } } } } else { for (let j = monsters.length - 1; j >= 0; j--) { const m = monsters[j]; if (Math.hypot(p.x - m.x, p.y - m.y) < (p.size || 4) + m.radius) { let dmg = p.damage, crit = false; if (Math.random() < player.criticalChance) { dmg *= 2; crit = true; } dmg = Math.floor(dmg * player.damageMultiplier); m.health -= dmg; if (p.weaponRef && p.weaponRef.isThrowable) p.weaponRef.trackKnifeHit(m); createDamageIndicator(m.x, m.y, dmg, crit); if (player.lifeSteal > 0) applyHealing(dmg * player.lifeSteal); if (m.isBoss && m.lifeSteal) { const bh = Math.floor(dmg * m.lifeSteal); if (bh > 0) { m.health = Math.min(m.maxHealth, m.health + bh); createHealthPopup(m.x, m.y, bh); } } if (p.isBoomerang && !p.targetsHit.includes(m)) p.targetsHit.push(m); if (!p.isBoomerang) { if (!p.bounceCount || !p.targetsHit) player.projectiles.splice(i, 1); else if (!p.targetsHit.includes(m)) p.targetsHit.push(m); } else if (p.isBoomerang && p.targetsHit.length >= p.maxTargets) { player.projectiles.splice(i, 1); break; } if (m.health <= 0) handleMonsterDeath(m, j); break; } } } } }
function updateMeleeAttacks() { const ct = Date.now(); for (let i = player.meleeAttacks.length - 1; i >= 0; i--) { const a = player.meleeAttacks[i]; if (ct - a.startTime > a.duration) { player.meleeAttacks.splice(i, 1); continue; } let hits = 0; for (let j = monsters.length - 1; j >= 0; j--) { const m = monsters[j]; if (Math.hypot(m.x - a.x, m.y - a.y) < a.radius + m.radius) { let dmg = a.damage, crit = false; if (Math.random() < player.criticalChance) { dmg *= 2; crit = true; } dmg = Math.floor(dmg * player.damageMultiplier); m.health -= dmg; createDamageIndicator(m.x, m.y, dmg, crit); if (player.lifeSteal > 0) applyHealing(dmg * player.lifeSteal); if (m.isBoss && m.lifeSteal) { const bh = Math.floor(dmg * m.lifeSteal); if (bh > 0) { m.health = Math.min(m.maxHealth, m.health + bh); createHealthPopup(m.x, m.y, bh); } } hits++; if (a.meleeType === 'pierce' && hits >= a.pierceCount) break; if (m.health <= 0) { handleMonsterDeath(m, j); j--; } } } } }
function updateMonsters(ct) { dashers = monsters.filter(m => m.isDasher); dashers.forEach(d => updateDasher(d, ct)); monsters.forEach(m => { if (m.slowed && m.slowUntil < ct) { m.slowed = false; m.speed = m.originalSpeed; } if (m.frozen && m.frozenUntil < ct) { m.frozen = false; m.speed = m.originalSpeed; } if (m.stunned && m.stunnedUntil < ct) m.stunned = false; if (m.stunned || m.frozen) return; if (m.isDasher && m.isDashing) return; let tx = player.x, ty = player.y, isTower = false, twr = null; if (playerTowers.healingTowers.active.length) { let bestDist = Infinity, best = null; playerTowers.healingTowers.active.forEach(t => { const d = Math.hypot(t.x - m.x, t.y - m.y); if (d < bestDist) { bestDist = d; best = t; } }); const toPlayer = Math.hypot(player.x - m.x, player.y - m.y); if (best && bestDist < toPlayer) { tx = best.x; ty = best.y; isTower = true; twr = best; } } const move = findPathToTarget(m, { x: tx, y: ty }); if (move.x !== 0 || move.y !== 0) { m.x += move.x * m.speed; m.y += move.y * m.speed; } if (m.isGunner && ct - m.lastAttack >= m.attackCooldown) { shootGunnerProjectile(m); m.lastAttack = ct; } if (m.isBoss && ct - m.lastAttack >= m.attackCooldown) { shootBossProjectiles(m); m.lastAttack = ct; } if (Math.hypot(tx - m.x, ty - m.y) < m.radius + (isTower ? 20 : player.radius) && ct - m.lastAttack >= m.attackCooldown) { if (isTower && twr) { twr.health -= m.damage; createDamageIndicator(twr.x, twr.y, m.damage, false); if (twr.health <= 0) { const idx = playerTowers.healingTowers.active.indexOf(twr); if (idx > -1) { playerTowers.healingTowers.active.splice(idx, 1); addVisualEffect({ type: 'explosion', x: twr.x, y: twr.y, radius: 30, color: '#8B0000', startTime: ct, duration: 300 }); queueMessage("Healing Tower destroyed!"); } } } else { let dmg = m.damage; if (Math.random() < player.dodgeChance) { queueMessage("DODGE!"); m.lastAttack = ct; return; } if (player.firstHitActive) { dmg *= 0.5; player.firstHitActive = false; queueMessage("Runic Plate absorbed 50% damage!"); } if (player.damageReduction > 0) dmg *= (1 - player.damageReduction); player.health -= dmg; if (m.isVampire && m.lifeSteal > 0) { const heal = Math.floor(dmg * m.lifeSteal); m.health = Math.min(m.maxHealth, m.health + heal); createHealthPopup(m.x, m.y, heal); } if (player.thornsDamage > 0) { const thorn = Math.floor(dmg * player.thornsDamage); if (thorn > 0) { m.health -= thorn; createDamageIndicator(m.x, m.y, thorn, false); } } createDamageIndicator(player.x, player.y, Math.floor(dmg), false); if (player.health <= 0) gameOver(); } m.lastAttack = ct; } }); }
function updateGroundEffects(ct) { for (let i = groundFire.length - 1; i >= 0; i--) { const f = groundFire[i]; if (ct - f.startTime > f.duration) { groundFire.splice(i, 1); continue; } monsters.forEach(m => { if (Math.hypot(m.x - f.x, m.y - f.y) < f.radius + m.radius) { if (!m.lastFireTick || ct - m.lastFireTick > 500) { m.health -= f.damage; createDamageIndicator(m.x, m.y, f.damage, false); m.lastFireTick = ct; } } }); } for (let i = poisonClouds.length - 1; i >= 0; i--) { const c = poisonClouds[i]; if (ct - c.startTime > c.duration) { poisonClouds.splice(i, 1); continue; } monsters.forEach(m => { if (Math.hypot(m.x - c.x, m.y - c.y) < c.radius + m.radius) { if (!m.lastPoisonTick || ct - m.lastPoisonTick > 500) { m.health -= c.damage; createDamageIndicator(m.x, m.y, c.damage, false); m.lastPoisonTick = ct; } } }); } for (let i = activeTraps.length - 1; i >= 0; i--) { const t = activeTraps[i]; if (!t.active) continue; monsters.forEach(m => { if (Math.hypot(m.x - t.x, m.y - t.y) < t.radius + m.radius) { m.health -= t.damage; createDamageIndicator(m.x, m.y, t.damage, true); t.active = false; } }); if (!t.active) activeTraps.splice(i, 1); } }
function addVisualEffect(e) { visualEffects.push(e); }
function updateVisualEffects() { const ct = Date.now(); for (let i = visualEffects.length - 1; i >= 0; i--) if (ct - visualEffects[i].startTime > visualEffects[i].duration) visualEffects.splice(i, 1); }
function drawVisualEffects() { const ct = Date.now(); visualEffects.forEach(e => { const p = (ct - e.startTime) / e.duration; if (p > 1) return; const a = 1 - p; ctx.save(); switch(e.type) { case 'death': ctx.fillStyle = `rgba(255,0,0,${a})`; for (let i = 0; i < 8; i++) { const ang = (Math.PI * 2 * i) / 8 + p * Math.PI, d = p * 30; ctx.beginPath(); ctx.arc(e.x + Math.cos(ang) * d, e.y + Math.sin(ang) * d, 3, 0, Math.PI * 2); ctx.fill(); } break; case 'spawn': ctx.strokeStyle = e.color || '#fff'; ctx.lineWidth = 3 * (1 - p); ctx.shadowColor = e.color || '#fff'; ctx.shadowBlur = 15 * a; for (let i = 0; i < 3; i++) { ctx.beginPath(); ctx.arc(e.x, e.y, 15 + i * 10 + p * 30, 0, Math.PI * 2); ctx.stroke(); } break; case 'bossSpawn': const grad = ctx.createRadialGradient(e.x, e.y, 0, e.x, e.y, e.radius); grad.addColorStop(0, `rgba(${e.color ? parseInt(e.color.slice(1,3),16) : 255}, ${e.color ? parseInt(e.color.slice(3,5),16) : 215}, 0, ${a})`); grad.addColorStop(0.5, `rgba(255,100,0,${a * 0.7})`); grad.addColorStop(1, 'rgba(0,0,0,0)'); ctx.fillStyle = grad; ctx.shadowColor = '#ffd700'; ctx.shadowBlur = 50; ctx.beginPath(); ctx.arc(e.x, e.y, e.radius * (1 - p * 0.5), 0, Math.PI * 2); ctx.fill(); break; case 'explosion': const sz = (e.radius || 40) * (1 - p * 0.5); const expGrad = ctx.createRadialGradient(e.x, e.y, 0, e.x, e.y, sz); expGrad.addColorStop(0, `rgba(255,255,255,${a})`); expGrad.addColorStop(0.3, `rgba(255,200,0,${a})`); expGrad.addColorStop(0.6, `rgba(255,100,0,${a * 0.7})`); expGrad.addColorStop(1, `rgba(255,0,0,0)`); ctx.fillStyle = expGrad; ctx.shadowColor = '#FF4500'; ctx.shadowBlur = 30; ctx.beginPath(); ctx.arc(e.x, e.y, sz, 0, Math.PI * 2); ctx.fill(); break; case 'heal': ctx.fillStyle = `rgba(0,255,0,${a * 0.3})`; ctx.shadowColor = '#0F0'; ctx.shadowBlur = 15 * a; ctx.beginPath(); ctx.arc(e.x, e.y, e.radius * (1 + p), 0, Math.PI * 2); ctx.fill(); break; default: break; } ctx.restore(); }); }
function drawMonsters() { const ct = Date.now(); monsters.forEach(m => { ctx.save(); ctx.translate(m.x, m.y); ctx.fillStyle = m.color; ctx.shadowColor = m.color; ctx.shadowBlur = m.isBoss ? 20 : 10; ctx.beginPath(); ctx.arc(0, 0, m.radius, 0, Math.PI * 2); ctx.fill(); if (m.stunned && m.stunnedUntil > ct) { ctx.fillStyle = 'rgba(255,255,0,0.3)'; ctx.beginPath(); ctx.arc(0, 0, m.radius, 0, Math.PI * 2); ctx.fill(); } if (m.frozen && m.frozenUntil > ct) { ctx.fillStyle = 'rgba(0,255,255,0.3)'; ctx.beginPath(); ctx.arc(0, 0, m.radius, 0, Math.PI * 2); ctx.fill(); } if (m.isDasher && m.isDashing) { ctx.strokeStyle = '#0FF'; ctx.lineWidth = 3; ctx.shadowColor = '#0FF'; ctx.shadowBlur = 15; ctx.beginPath(); ctx.arc(0, 0, m.radius + 5, 0, Math.PI * 2); ctx.stroke(); } if (m.isVampire) { ctx.strokeStyle = '#F00'; ctx.lineWidth = 2; ctx.shadowColor = '#F00'; ctx.shadowBlur = 10; ctx.beginPath(); ctx.arc(0, 0, m.radius + 3, 0, Math.PI * 2); ctx.stroke(); } ctx.shadowBlur = 0; ctx.strokeStyle = '#000'; ctx.lineWidth = 2; ctx.beginPath(); ctx.arc(0, 0, m.radius, 0, Math.PI * 2); ctx.stroke(); if (m.monsterType && m.monsterType.icon) { ctx.fillStyle = 'white'; ctx.font = `${m.radius}px Arial`; ctx.textAlign = 'center'; ctx.textBaseline = 'middle'; ctx.fillText(m.monsterType.icon, 0, 0); } const a = Math.atan2(player.y - m.y, player.x - m.x), eyeR = m.radius * 0.2; ctx.fillStyle = '#FFF'; ctx.shadowBlur = 5; ctx.beginPath(); ctx.arc(Math.cos(a - 0.3) * m.radius * 0.6, Math.sin(a - 0.3) * m.radius * 0.6, eyeR, 0, Math.PI * 2); ctx.fill(); ctx.beginPath(); ctx.arc(Math.cos(a + 0.3) * m.radius * 0.6, Math.sin(a + 0.3) * m.radius * 0.6, eyeR, 0, Math.PI * 2); ctx.fill(); ctx.fillStyle = '#000'; ctx.shadowBlur = 0; ctx.beginPath(); ctx.arc(Math.cos(a) * m.radius * 0.7, Math.sin(a) * m.radius * 0.7, eyeR * 0.5, 0, Math.PI * 2); ctx.fill(); const hpPct = Math.max(0, Math.min(1, m.health / m.maxHealth)); const bw = m.radius * 2, bh = 4, bx = -m.radius, by = -m.radius - 10; ctx.fillStyle = 'rgba(0,0,0,0.7)'; ctx.fillRect(bx, by, bw, bh); if (hpPct > 0) { ctx.fillStyle = hpPct > 0.5 ? '#0F0' : (hpPct > 0.2 ? '#FF0' : '#F00'); ctx.fillRect(bx, by, bw * hpPct, bh); } ctx.restore(); }); }
function createDamageIndicator(x, y, dmg, crit) { const el = document.createElement('div'); el.className = 'damage-indicator'; el.textContent = dmg.toString(); if (crit) { el.textContent = 'CRIT! ' + dmg; el.style.color = '#FFD700'; el.style.fontSize = '1.5rem'; } el.style.left = (x + Math.random() * 20 - 10) + 'px'; el.style.top = (y + Math.random() * 20 - 10) + 'px'; document.querySelector('.canvas-container').appendChild(el); setTimeout(() => { if (el.parentNode) el.parentNode.removeChild(el); }, 1000); }
function createGoldPopup(x, y, amt) { const el = document.createElement('div'); el.className = 'gold-popup'; el.textContent = '+' + amt + 'g'; el.style.left = (x + Math.random() * 20 - 10) + 'px'; el.style.top = (y + Math.random() * 20 - 10) + 'px'; document.querySelector('.canvas-container').appendChild(el); setTimeout(() => { if (el.parentNode) el.parentNode.removeChild(el); }, 1000); }
function createHealthPopup(x, y, amt) { const el = document.createElement('div'); el.className = 'health-popup'; el.textContent = '+' + amt + ' HP'; el.style.left = (x + Math.random() * 20 - 10) + 'px'; el.style.top = (y + Math.random() * 20 - 10) + 'px'; document.querySelector('.canvas-container').appendChild(el); setTimeout(() => { if (el.parentNode) el.parentNode.removeChild(el); }, 1000); }
function createStatsButton() { const btn = document.createElement('button'); btn.id = 'statsButton'; btn.className = 'stats-button'; btn.innerHTML = '📊 Stats'; btn.addEventListener('click', toggleStatsPanel); btn.addEventListener('touchstart', (e) => { e.preventDefault(); toggleStatsPanel(); }); document.body.appendChild(btn); }

document.addEventListener('keydown', (e) => { const k = e.key.toLowerCase(); if (k === 'w' || k === 'arrowup') { keys.w = true; keys.up = true; e.preventDefault(); } if (k === 's' || k === 'arrowdown') { keys.s = true; keys.down = true; e.preventDefault(); } if (k === 'a' || k === 'arrowleft') { keys.a = true; keys.left = true; e.preventDefault(); } if (k === 'd' || k === 'arrowright') { keys.d = true; keys.right = true; e.preventDefault(); } if (k === ' ') { if (gameState === 'shop') { keys.space = true; nextWaveBtn.click(); } e.preventDefault(); } if (k === 'r') { if (gameState === 'shop') { player.weapons.forEach(w => { if (w.usesAmmo && !w.isReloading && !w.isThrowable) w.startReload(); }); } e.preventDefault(); } if (k === 's' && e.ctrlKey) { e.preventDefault(); saveGame(); } if (k === 'l' && e.ctrlKey) { e.preventDefault(); loadGame(); } });
document.addEventListener('keyup', (e) => { const k = e.key.toLowerCase(); if (k === 'w' || k === 'arrowup') { keys.w = false; keys.up = false; e.preventDefault(); } if (k === 's' || k === 'arrowdown') { keys.s = false; keys.down = false; e.preventDefault(); } if (k === 'a' || k === 'arrowleft') { keys.a = false; keys.left = false; e.preventDefault(); } if (k === 'd' || k === 'arrowright') { keys.d = false; keys.right = false; e.preventDefault(); } if (k === ' ') { keys.space = false; e.preventDefault(); } });
canvas.addEventListener('touchstart', (e) => { e.preventDefault(); const t = e.touches[0], rect = canvas.getBoundingClientRect(); mouseX = t.clientX - rect.left; mouseY = t.clientY - rect.top; touchStartTime = Date.now(); touchMoved = false; lastTouchX = mouseX; lastTouchY = mouseY; });
canvas.addEventListener('touchmove', (e) => { e.preventDefault(); const t = e.touches[0], rect = canvas.getBoundingClientRect(); mouseX = t.clientX - rect.left; mouseY = t.clientY - rect.top; touchMoved = true; });
canvas.addEventListener('touchend', (e) => { e.preventDefault(); });
canvas.addEventListener('touchcancel', (e) => { e.preventDefault(); });
canvas.addEventListener('mousemove', (e) => { const rect = canvas.getBoundingClientRect(); mouseX = e.clientX - rect.left; mouseY = e.clientY - rect.top; });
startGameBtn.addEventListener('click', (e) => { e.preventDefault(); initGame(); });
startGameBtn.addEventListener('touchstart', (e) => { e.preventDefault(); initGame(); });
nextWaveBtn.addEventListener('click', (e) => { e.preventDefault(); if (gameState === 'shop') { gameState = 'wave'; startWave(); nextWaveBtn.style.display = 'none'; scrapWeaponBtn.style.display = 'none'; mergeWeaponBtn.style.display = 'none'; selectedWeaponIndex = -1; mergeTargetIndex = -1; } });
nextWaveBtn.addEventListener('touchstart', (e) => { e.preventDefault(); if (gameState === 'shop') { gameState = 'wave'; startWave(); nextWaveBtn.style.display = 'none'; scrapWeaponBtn.style.display = 'none'; mergeWeaponBtn.style.display = 'none'; selectedWeaponIndex = -1; mergeTargetIndex = -1; } });
scrapWeaponBtn.addEventListener('click', (e) => { e.preventDefault(); scrapWeapon(); });
scrapWeaponBtn.addEventListener('touchstart', (e) => { e.preventDefault(); scrapWeapon(); });
mergeWeaponBtn.addEventListener('click', (e) => { e.preventDefault(); mergeWeapons(); });
mergeWeaponBtn.addEventListener('touchstart', (e) => { e.preventDefault(); mergeWeapons(); });
refreshShopBtn.addEventListener('click', (e) => { e.preventDefault(); refreshShop(); });
refreshShopBtn.addEventListener('touchstart', (e) => { e.preventDefault(); refreshShop(); });
restartBtn.addEventListener('click', (e) => { e.preventDefault(); gameOverOverlay.style.display = 'none'; clearSave(); initGame(); });
restartBtn.addEventListener('touchstart', (e) => { e.preventDefault(); gameOverOverlay.style.display = 'none'; clearSave(); initGame(); });

